const validatePromoCode = (code: string): { valid: boolean; error?: string } => {
  const normalized = code.trim().toUpperCase();
  const allowedCodes = ["SAVE10", "WELCOME10"];
  if (!normalized) return { valid: false, error: "Enter a promo code." };
  if (!allowedCodes.includes(normalized)) return { valid: false, error: "Invalid promo code." };
  return { valid: true };
};

const handleApplyPromo = () => {
  const result = validatePromoCode(promoCode);
  if (!result.valid) {
    setPromoApplied(false);
    setPromoError(result.error ?? "Invalid promo code.");
    return;
  }
  setPromoError("");
  setPromoApplied(true);
};
